    45→/**
    46→ * Maps an OWL class to an OpenAPI Schema object.
    47→ *
    48→ * <p>This mapper analyzes an OWL class from the ontology and generates a corresponding
    49→ * OpenAPI 3.1 ObjectSchema with properties derived from:
    50→ * <ul>
    51→ *   <li><b>Data properties</b> - mapped to primitive schema types (string, integer, etc.)</li>
    52→ *   <li><b>Object properties</b> - mapped to $ref references or inline schemas</li>
    53→ *   <li><b>Taxonomy properties</b> - mapped to enum schemas based on named individuals</li>
    54→ * </ul>
    55→ *
    56→ * <h2>Processing Pipeline</h2>
    57→ * <pre>
    58→ * OWLClass → SchemaVisitor → Axiom Collection → Restriction Collection
    59→ *                                   ↓
    60→ *        ┌────────────────────────────────────────────┐
    61→ *        │                                            │
    62→ *        ▼                    ▼                       ▼
    63→ *  DataPropertyMapper   ObjectPropertyMapper   TaxonomyPropertyMapper
    64→ *        │                    │                       │
    65→ *        └────────────────────┴───────────────────────┘
    66→ *                             ↓
    67→ *                     OpenAPI ObjectSchema
    68→ * </pre>
    69→ *
    70→ * <h2>Annotation Filtering</h2>
    71→ * <p>Only axioms annotated with {@code apiLabel} matching the schema label from
    72→ * {@link MappingContext#getSchemaLabel()} are included in the generated schema.
    73→ *
    74→ * <h2>Thread Safety</h2>
    75→ * <p>This class is <b>not thread-safe</b>. Each instance should be used to map
    76→ * a single OWL class and then discarded.
    77→ *
    78→ * @see DataPropertyMapper
    79→ * @see ObjectPropertyMapper
    80→ * @see TaxonomyPropertyMapper
    81→ * @see SchemaVisitor
    82→ */
    83→public class ResourceSchemaMapper {
    84→
    85→  /**
    86→   * Holds categorized axiom collections for the analyzed class.
    87→   *
    88→   * @param taxonomy axioms referencing named individuals (enum values)
    89→   * @param subClass direct SubClassOf axioms for the analyzed class
    90→   * @param superClass inherited axioms from the class hierarchy
    91→   */
    92→  private record AxiomCollection(
    93→      List<OWLSubClassOfAxiom> taxonomy,
    94→      List<OWLSubClassOfAxiom> subClass,
    95→      List<OWLSubClassOfAxiom> superClass) {}
    96→  private static final Logger logger = Logger.getLogger(ResourceSchemaMapper.class.getName());
    97→  private final MappingContext context;
    98→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
    99→  private final String type;
   100→  private final OWLClass cls;
   101→  private final String classDescription;
   102→  private final String name;
   103→  private final Schema<?> schema;
   104→
   105→  public Schema<?> getSchema() {
   106→    return schema;
   107→  }
   108→
   109→  public String getName() {
   110→    return name;
   111→  }
   112→
   113→  public ResourceSchemaMapper(MappingContext context, OWLClass cls, String clsDescription) {
   114→    this.context = context;
   115→    this.cls = cls;
   116→    this.classDescription = clsDescription;
   117→    this.type = "object";
   118→    this.name = nameResolver.resolve(cls);
   119→    this.schema = createSchema(cls);
   120→  }
   121→
   122→  /**
   123→   * Creates the OpenAPI schema for the analyzed OWL class.
   124→   *
   125→   * <p>This method orchestrates the schema generation by:
   126→   * <ol>
   127→   *   <li>Initializing the base ObjectSchema with metadata</li>
   128→   *   <li>Creating a visitor to traverse class restrictions</li>
   129→   *   <li>Collecting relevant axioms from the ontology</li>
   130→   *   <li>Visiting axioms to gather property restrictions</li>
   131→   *   <li>Processing data, object, and taxonomy properties</li>
   132→   * </ol>
   133→   *
   134→   * @param analyzedClass the OWL class to generate a schema for
   135→   * @return the generated OpenAPI Schema object
   136→   */
   137→  private Schema<?> createSchema(OWLClass analyzedClass) {
   138→    Schema<?> schema = initializeResourceSchema();
   139→
   140→    SchemaVisitor visitor = createSchemaVisitor(analyzedClass);
   141→    AxiomCollection axioms = collectRelevantAxioms(analyzedClass);
   142→
   143→    visitAxioms(visitor, axioms);
   144→
   145→    Map<String, Set<RestrictionInfo>> restrictions = visitor.getRestrictions();
   146→
   147→    processDataProperties(schema, visitor, restrictions, axioms.subClass());
   148→    processObjectProperties(schema, visitor, restrictions);
   149→    processTaxonomyProperties(schema, axioms.taxonomy(), visitor, restrictions);
   150→
   151→    if (schema.getProperties() == null || schema.getProperties().isEmpty()) {
   152→      logMissingPropertiesWarning(analyzedClass, axioms);
   153→    }
   154→
   155→    return schema;
   156→  }
   157→
   158→  /**
   159→   * Creates and configures the base ObjectSchema with standard properties.
   160→   *
   161→   * @return a new ObjectSchema configured with name, type, description, and OpenAPI 3.1 spec version
   162→   */
   163→  private Schema<?> initializeResourceSchema() {
   164→    Schema<?> resourceSchema = new ObjectSchema();
   165→    resourceSchema.setSpecVersion(SpecVersion.V31);
   166→    resourceSchema.setName(this.name);
   167→    resourceSchema.setDescription(this.classDescription);
   168→    resourceSchema.setType(this.type);
   169→    resourceSchema.setAdditionalProperties(false);
   170→    resourceSchema.setTitle(getLabel(this.cls));
   171→    return resourceSchema;
   172→  }
   173→
   174→  /**
   175→   * Creates a SchemaVisitor for analyzing class restrictions.
   176→   *
   177→   * <p>A single visitor collects both object property and data property restrictions,
   178→   * as the OWL visitor dispatch is type-safe and SchemaVisitor internally separates
   179→   * property types.
   180→   *
   181→   * @param analyzedClass the OWL class to analyze
   182→   * @return the configured visitor
   183→   */
   184→  private SchemaVisitor createSchemaVisitor(OWLClass analyzedClass) {
   185→    OWLDataFactory dataFactory = context.getManager().getOWLDataFactory();
   186→    OWLClass owlThing = dataFactory.getOWLThing();
   187→    return new SchemaVisitor(analyzedClass, context.getOntology(), owlThing);
   188→  }
   189→
   190→  /**
   191→   * Collects all relevant axioms for the analyzed class from the ontology.
   192→   *
   193→   * <p>Gathers three categories of axioms:
   194→   * <ul>
   195→   *   <li><b>Taxonomy axioms</b>: SubClassOf axioms referencing named individuals (enum values)</li>
   196→   *   <li><b>SubClass axioms</b>: Direct SubClassOf axioms for the analyzed class</li>
   197→   *   <li><b>SuperClass axioms</b>: Inherited axioms from the class hierarchy</li>
   198→   * </ul>
   199→   *
   200→   * @param analyzedClass the OWL class to collect axioms for
   201→   * @return a record containing categorized axiom lists
   202→   */
   203→  private AxiomCollection collectRelevantAxioms(OWLClass analyzedClass) {
   204→    OWLOntology ontology = context.getOntology();
   205→    return new AxiomCollection(
   206→        getTaxonomyAxioms(analyzedClass),
   207→        ontology.subClassAxiomsForSubClass(analyzedClass).toList(),
   208→        getSuperClassAxioms(analyzedClass, null).toList());
   209→  }
   210→
   211→  /**
   212→   * Visits axioms with the schema visitor to collect restrictions.
   213→   *
   214→   * <p>For each axiom, the superclass expression is visited by the visitor.
   215→   * The OWL visitor dispatch is type-safe, so a single visitor correctly handles
   216→   * both object and data property restrictions.
   217→   *
   218→   * <p>Taxonomy axioms are also visited to detect taxonomy patterns (A, B, C, D)
   219→   * via SchemaVisitor's taxonomy pattern detector.
   220→   *
   221→   * @param visitor the schema visitor to use
   222→   * @param axioms the axiom collection to process
   223→   */
   224→  private void visitAxioms(SchemaVisitor visitor, AxiomCollection axioms) {
   225→    String schemaLabel = context.getSchemaLabel();
   226→
   227→    // Filter axioms to only those annotated with the target apiLabel
   228→    // This allows multiple API schemas to be generated from the same ontology
   229→    axioms.subClass().stream()
   230→        .filter(axiom -> !axioms.taxonomy().contains(axiom))
   231→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, schemaLabel))
   232→        .map(OWLSubClassOfAxiom::getSuperClass)
   233→        .forEach(superClass -> superClass.accept(visitor));
   234→
   235→    axioms.superClass().stream()
   236→        .map(OWLSubClassOfAxiom::getSuperClass)
   237→        .forEach(superClass -> superClass.accept(visitor));
   238→
   239→    // Also visit taxonomy axioms for pattern detection
   240→    // This enables detectTaxonomyPattern to be called for Pattern B individuals
   241→    axioms.taxonomy().stream()
   242→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, schemaLabel))
   243→        .map(OWLSubClassOfAxiom::getSuperClass)
   244→        .forEach(superClass -> superClass.accept(visitor));
   245→  }
