    47→public class Asg {
    48→
    49→  private static final Logger logger = Logger.getLogger(Asg.class.getName());
    50→
    51→  static {
    52→    try {
    53→      InputStream stream = Asg.class.getResourceAsStream("logging.properties");
    54→      LogManager.getLogManager().readConfiguration(stream);
    55→    } catch (Exception e) {
    56→      throw new RuntimeException(e);
    57→    }
    58→    SimpleModule simpleModule = new SimpleModule().addSerializer(new JsonNodeExampleSerializer());
    59→    Json.mapper().registerModule(simpleModule);
    60→  }
    61→
    62→  private final YamlConfig config;
    63→
    64→  private Asg(YamlConfig config) {
    65→    this.config = Objects.requireNonNull(config);
    66→  }
    67→
    68→  void generate() {
    69→    logger.info("Preparing ontology and generating api");
    70→    ensureAPIOutputDirExists();
    71→    saveEffectiveConfig();
    72→    generateOpenApiSpecs(addSecurityScheme(addExamples(OntologyMapper.map(config))));
    73→  }
    74→
    75→  void flattenOnly() {
    76→    logger.info("Option --no-generate selected: will output prepared ontology from given config");
    77→    ensureAPIOutputDirExists();
    78→    saveEffectiveConfig();
    79→    new OntologyMapper(config); // loads and outputs ontology
    80→  }
    81→
    82→  private void ensureAPIOutputDirExists() {
    83→    Path outputDir = config.getApiOutputDir();
    84→    if (!outputDir.toFile().exists()) {
    85→      boolean mkdirs = outputDir.toFile().mkdirs();
    86→      if (!mkdirs) {
    87→        throw new RuntimeException("Failed to create output directory: " + outputDir);
    88→      }
    89→    }
    90→  }
    91→
    92→  private void saveEffectiveConfig() {
    93→    try {
    94→      Yaml.mapper().writeValue(config.getApiOutputDir().resolve("effective-config.yaml").toFile(), config);
    95→    } catch (IOException e) {
    96→      throw new RuntimeException(e);
    97→    }
    98→
    99→  }
   100→
   101→  public static void main(String[] args) {
   102→    try {
   103→      CommandLine commandLine = parseCommandLine(args);
   104→      YamlConfig config = Config.load(Path.of(commandLine.getOptionValue("config")));
   105→
   106→      // if output dir on command line apply to config
   107→      Optional.ofNullable(commandLine.getOptionValue("output-dir"))
   108→          .map(Path::of)
   109→          .map(Path::toAbsolutePath)
   110→          .ifPresent(config::setOutputDir);
   111→      if (commandLine.hasOption("ontology-file")) {
   112→        // ontology provided on command line - override config
   113→        String ontologyFile = commandLine.getOptionValue("ontology-file");
   114→        config.setOntologies(List.of(ontologyFile.matches("^\\w+://") ? new URI(ontologyFile)
   115→            : Path.of(ontologyFile).toAbsolutePath().toUri()));
   116→      }
   117→      // if output dir on command line apply to config
   118→      Optional.ofNullable(commandLine.getOptionValue("output-dir"))
   119→          .map(Path::of)
   120→          .map(Path::toAbsolutePath)
   121→          .ifPresent(config::setOutputDir);
   122→
   123→      Asg asg = new Asg(config);
   124→      if (commandLine.hasOption("no-generate")) {
   125→        asg.flattenOnly();
   126→      } else {
   127→        asg.generate();
   128→      }
   129→    } catch (Exception e) {
   130→      logger.severe(e.getMessage());
   131→      throw new RuntimeException(e);
   132→    }
   133→  }
   134→
   135→  private static CommandLine parseCommandLine(String[] args) {
   136→    // obtain the options to pass configuration
   137→    Options options = new Options();
   138→    Option config = new Option("c", "config", true, "configuration file path");
   139→    config.setRequired(true);
   140→    options.addOption(config);
   141→    options.addOption(
   142→        new Option("f", "ontology-file", true, "override the ontology file specified in config"));
   143→    options.addOption(
   144→        new Option("o", "output-dir", true, "override the output directpry specified in config"));
   145→    options.addOption(new Option("G", "no-generate", false,
   146→        "stop after loading ontology and output flattened version"));
   147→
   148→    try {
   149→      return new DefaultParser().parse(options, args);
   150→    } catch (ParseException e) {
   151→      new HelpFormatter().printHelp("Asg", options);
   152→      throw new RuntimeException(e);
   153→    }
   154→
   155→  }
